    let n = grid[0].len();
    let dirs = [(0, 1), (1, 0)]; // right, down

    // Priority queue: (total_cost, x, y, num_transports_used)
    let mut pq = std::collections::BinaryHeap::new();
    pq.push((grid[0][0], 0, 0, 0));

    // dp[i][j][k] = minimum cost to reach (i, j) with k transports used
    let mut dp = vec![vec![vec![i64::MAX; (k as usize + 1)]; n]; m];
